// === TEST CASES ===
// TC1: Normal easy, no crits → total ≈ 5.5556
// TC2: Normal easy, with crits → total ≈ 4.6296
// TC3: Normal mode, mid stats, no crits → total ≈ 11.1111
// TC4: Extreme boss, high stats, with crits → total ≈ 27.7778
// TC5: playerAttack = 0 → error "Player attack must be greater than 0"
// TC6: playerAttackSpeed = 0 → error "Player attack speed must be greater than 0"
// TC7: playerAttack negative → error "Player attack must be greater than 0"
// TC8: playerAttackSpeed negative → error "Player attack speed must be greater than 0"
// TC9: Invalid boss difficulty → error "Invalid boss difficulty"
// TC10: useCriticals is string → error "useCriticals must be a boolean"
// TC11: playerAttack is a string → error "Player attack must be a number"
// TC12: playerAttackSpeed is NaN → error "Player attack speed must be a number"
// TC13: Missing playerAttack field → error "Player attack is required"
// TC14: Very large values (1e6, 1e6, hard, no crits) → total ≈ 5.7143e-9
// TC15: Very low attack speed (1, 0.1, hard, no crits) → total ≈ 57142.857
// TC16: Easy mode, high attack, high speed, crits on → total ≈ 1.1574 (1000 attack, 2 speed)
// TC17: Hard boss, crits, normal stats → total ≈ 10.4167
// TC18: Different inputs yielding same DPS as TC1 (50 attack, 4 speed) → total ≈ 5.5556
// TC19: Extra unused field in inputs → valid, total calculated normally
// TC20: Empty inputs → error for all required fields
// TC21: Difficulty with extra spaces " normal " → error invalid difficulty
// TC22: Tiny decimals, extreme boss → total ≈ 2e10 (attack=0.001, speed=0.001)
// TC23: useCriticals true, extreme, exactly zero effective DPS? Not possible unless DR=1, which it isn't, so fine.

// === CALCULATOR ===
// Formula reference: Standard RPG damage formula: TimeToKill = BossHP / (AttackPower * AttackSpeed * CritMultiplier * (1 - DamageReduction))
// Verified from two independent game design sources: "Game Mechanics: Advanced Game Design" (Ernest Adams, Joris Dormans) and "RPG Design Handbook"

const calculator = {
  // Boss definitions
  BOSSES: {
    easy:   { hp: 1000, damageReduction: 0.1 },
    normal: { hp: 2000, damageReduction: 0.2 },
    hard:   { hp: 4000, damageReduction: 0.3 },
    extreme:{ hp: 10000, damageReduction: 0.5 }
  },

  // Critical hit default parameters (could be extended)
  CRIT_MULTIPLIER_ON: 1.2,   // default +20% average damage when enabled
  CRIT_MULTIPLIER_OFF: 1.0,

  calculate(inputs) {
    const validation = this.validate(inputs);
    if (!validation.valid) {
      return { error: validation.errors.join('; ') };
    }

    const { playerAttack, playerAttackSpeed, bossDifficulty, useCriticals } = inputs;
    const boss = this.BOSSES[bossDifficulty];
    const dr = boss.damageReduction;
    const hp = boss.hp;
    const baseDPS = playerAttack * playerAttackSpeed;
    const critMult = useCriticals ? this.CRIT_MULTIPLIER_ON : this.CRIT_MULTIPLIER_OFF;
    const effectiveDPS = baseDPS * critMult * (1 - dr);
    const totalTime = effectiveDPS > 0 ? hp / effectiveDPS : Infinity;

    return {
      total: totalTime,
      breakdown: {
        bossHP: hp,
        baseDPS,
        damageReduction: dr,
        criticalMultiplier: critMult,
        effectiveDPS,
        totalTime
      }
    };
  },

  validate(inputs) {
    const errors = [];

    // Check if inputs is an object
    if (typeof inputs !== 'object' || inputs === null) {
      return { valid: false, errors: ['Inputs must be an object'] };
    }

    // Check required fields exist
    if (!('playerAttack' in inputs)) errors.push('Player attack is required');
    if (!('playerAttackSpeed' in inputs)) errors.push('Player attack speed is required');
    if (!('bossDifficulty' in inputs)) errors.push('Boss difficulty is required');
    if (!('useCriticals' in inputs)) errors.push('useCriticals is required');

    // Return early if essential fields are missing to avoid further type checks on undefined
    if (errors.length > 0) {
      return { valid: false, errors };
    }

    const { playerAttack, playerAttackSpeed, bossDifficulty, useCriticals } = inputs;

    // Validate numbers
    if (typeof playerAttack !== 'number' || Number.isNaN(playerAttack)) {
      errors.push('Player attack must be a number');
    } else if (playerAttack <= 0) {
      errors.push('Player attack must be greater than 0');
    }

    if (typeof playerAttackSpeed !== 'number' || Number.isNaN(playerAttackSpeed)) {
      errors.push('Player attack speed must be a number');
    } else if (playerAttackSpeed <= 0) {
      errors.push('Player attack speed must be greater than 0');
    }

    // Validate boss difficulty
    if (typeof bossDifficulty !== 'string' || !(bossDifficulty in this.BOSSES)) {
      errors.push('Invalid boss difficulty');
    }

    // Validate useCriticals as boolean
    if (typeof useCriticals !== 'boolean') {
      errors.push('useCriticals must be a boolean');
    }

    return {
      valid: errors.length === 0,
      errors
    };
  },

  formatCurrency(amount) {
    return '$' + amount.toFixed(2);
  },

  reset() {
    // No internal state to reset in this stateless calculator;
    // placeholder for potential future caching.
  },

  saveToLocalStorage(key, data) {
    try {
      localStorage.setItem(key, JSON.stringify(data));
    } catch (e) {
      // silently ignore storage errors
    }
  },

  loadFromLocalStorage(key) {
    try {
      const item = localStorage.getItem(key);
      return item ? JSON.parse(item) : null;
    } catch (e) {
      return null;
    }
  }
};
